import{_ as a,o as e,c as i,a0 as p}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Profile（简介）","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"学习文章/简介.md","filePath":"学习文章/简介.md"}'),n={name:"学习文章/简介.md"};function t(l,s,o,d,h,r){return e(),i("div",null,[...s[0]||(s[0]=[p(`<h1 id="profile-简介" tabindex="-1">Profile（简介） <a class="header-anchor" href="#profile-简介" aria-label="Permalink to &quot;Profile（简介）&quot;">​</a></h1><p>Hello👋 I&#39;m MeiEddie</p><p>Born in May 2008, currently live in China</p><p>A recreational coder &amp; student who records learning journey</p><p>This is Eddie&#39;s static blog</p><h2 id="本站建设" tabindex="-1">本站建设 <a class="header-anchor" href="#本站建设" aria-label="Permalink to &quot;本站建设&quot;">​</a></h2><p>如果你有任何建议或问题，欢迎提出</p><p>电子邮箱：3648939315@qq.com</p><h3 id="信息同步" tabindex="-1">信息同步 <a class="header-anchor" href="#信息同步" aria-label="Permalink to &quot;信息同步&quot;">​</a></h3><p>本地编辑，随缘同步</p><h2 id="如何搭建本站" tabindex="-1">如何搭建本站 <a class="header-anchor" href="#如何搭建本站" aria-label="Permalink to &quot;如何搭建本站&quot;">​</a></h2><h3 id="vitepress-github托管" tabindex="-1">VitePress+GitHub托管 <a class="header-anchor" href="#vitepress-github托管" aria-label="Permalink to &quot;VitePress+GitHub托管&quot;">​</a></h3><br><h5 id="选择的理由" tabindex="-1">选择的理由 <a class="header-anchor" href="#选择的理由" aria-label="Permalink to &quot;选择的理由&quot;">​</a></h5><p>搭建网站有许多方法，这只是其中一种，适合自己才是最好的</p><p>不选择纯手写html：文章多了难以维护。</p><p>VitePress是由Vue官方开发免费、开源、专门做静态文档/博客网站的工具。选择VitePress底层技术纯静态网站，可直接托管GitHub Pages，便于学习使用（免费）。</p><p>笔记使用Markdown书写，只要新建.md文件就可以记录学习笔记。单人维护量比较少，维护成本低。</p><h5 id="什么是node-js" tabindex="-1">什么是Node.js <a class="header-anchor" href="#什么是node-js" aria-label="Permalink to &quot;什么是Node.js&quot;">​</a></h5><p>Node.js可以理解为VitePress的运行环境，VitePress是用JS写的程序，没有node就打不开。</p><blockquote><p>JavaScript是车，nodejs是路，你写的代码跑在nodejs上就相当于造的车跑在路上。有的路是高速公路叫v8，有的路是赛车道叫bun。（来自bilibili@月霞右侍郎）</p></blockquote><p>除了提供运行环境的作用之外，Node.js还包含管理器npm，可一键下载VitePress。</p><blockquote><p>有人或许听过Nest.js，Nest.js是一套基于Node.js的后端开发框架，底层依赖Node.js，貌似使用情景比较少？这里我们不会用到。</p></blockquote><h5 id="从node-js到vitepress" tabindex="-1">从Node.js到VitePress <a class="header-anchor" href="#从node-js到vitepress" aria-label="Permalink to &quot;从Node.js到VitePress&quot;">​</a></h5><p>官网下载：<a href="https://nodejs.org/zh-cn/download" target="_blank" rel="noreferrer">https://nodejs.org/zh-cn/download</a></p><p>官网安装有两个选择（安装程序.msi/独立文件.zip），我们选择Windows安装程序 (.msi)，自己选择安装路径。</p><blockquote><p>路径不要带中文、空格（别用D:\\我的程序\\node这样子的），容易后面npm报错</p></blockquote><p>之后按照安装提示一直点next</p><blockquote><p>不需要勾选Tools for Native Modules的复选框，只用VitePress搭建静态博客，不需要编译 C/C++ 原生模块，这些工具无用，勾选只会增加冗余软件。之后要用到的话也可以安装回来。</p></blockquote><p>新建一个安装文件夹（因为里面的文件是分散的），安装完成之后就能看到下载的文件啦，包括node_modules文件夹和其他各种文件。</p><p>先验证Node是否安装成功：</p><ol><li>按下键盘 Win + R，输入 cmd 回车，打开黑色命令窗口</li><li>依次输入下面两条命令，每条输完按回车：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span></code></pre></div><p>如果输出版本号（比如 v20.15.0、10.8.2）,说明安装成功</p><p>新建博客文件夹，初始化VitePress笔记站：</p><ol><li>在电脑非C盘新建文件夹，比如D:\\study-blog</li><li>在文件夹地址栏输入cmd回车，直接打开当前目录的终端</li><li>复制执行初始化命令：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vitepress</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>输入y，Ok to proceed，它一开始要等一会（可能要1~2分钟），一切顺利的话我们就进行下一步</p><blockquote><p>如果等待超过5分钟完全没输出，就是网络超时，按Ctrl+C终止，然后自己想办法（加油）</p></blockquote><p>之后它会问你问题：</p><p>Where should VitePress initialize the config?回答./docs（它会给你./）</p><blockquote><p>问你title，description，可以随便写（中英文都可以），不喜欢之后可以改</p></blockquote><p>Theme：选择Default Theme</p><p>Use TypeScript for config and theme files? 选择No</p><p>Add VitePress npm scripts to package.json? 选择Yes</p><ol start="4"><li>安装依赖</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><ol start="5"><li>启动本地博客预览</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:dev</span></span></code></pre></div><blockquote><p>如果报错：&#39;vitepress&#39;不是内部或外部命令，也不是可运行的程序或批处理文件。说明项目本地的vitepress依赖没有正确安装，在当前对话框内输入：</p></blockquote><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vitepress</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --save-dev</span></span></code></pre></div><p>出现漏洞警告大概率也没关系，不影响博客正常使用。</p><p>运行完之后再次进行步骤5：输入npm run docs:dev</p><p>运行成功后，终端会给出地址<code>http://localhost:5173</code>，复制到浏览器就能打开你的网页（在这里点也可以）。</p><h5 id="一些疑问" tabindex="-1">一些疑问 <a class="header-anchor" href="#一些疑问" aria-label="Permalink to &quot;一些疑问&quot;">​</a></h5><p><strong>为什么是这个网址</strong></p><p>VitePress底层是基于Vite开发的，Vite开发服务器默认端口固定为5173，这是官方设定好的标准端口号，所以只要本地没被占用，启动后一定是这个网址。</p><p>旧版Vite曾用3000，所以在一些网上的教程中你会看到网址是<code>http://localhost:3000</code>。</p><p>不过当然还是看你的终端怎么显示，复制就行了，终端会显示真实地址。</p><p><strong>现在CMD窗口能不能关</strong></p><p>取决于现在你是否需要实时编译，现在你在文件夹中更改，浏览器的网页也会实时更新（文件要保存）。关掉CMD窗口网页也会进不去，不需要的情况下可以关掉。想要再次打开只需要在你新建的那个文件夹地址栏输入cmd回车，进行步骤5即可（上文）。</p><p><strong>如何开始编辑</strong></p><p>.vitepress是配置文件夹，用来改标题、导航栏、侧边栏、搜索、GitHub链接等设置。</p><p>index.md文件是首页，可修改首页布局、封面。</p><p>api-examples.md / markdown-examples.md是官方示例文档，新手可借此学习，可以删掉。</p><p>在docs新建<code>.md</code>格式文件，侧边栏分类需要去到你的<code>config.mjs</code>文件更改，<code>.md</code>格式文件则是你的文章。</p><h5 id="github托管" tabindex="-1">Github托管 <a class="header-anchor" href="#github托管" aria-label="Permalink to &quot;Github托管&quot;">​</a></h5><p>首先，你需要有一个Github帐号</p><p>然后，创建仓库，命名为<code>你的用户名.github.io</code>（要完全一致），选择Public，创建</p><p>将你的文件夹内的文件上传GitHub（可使用Git、Github Desktop等等）</p><blockquote><p>注意node_modules文件夹不要上传，文件很大且不需要，影响上传。最好能写一份<code>.gitignore</code>把它隐藏防止操作失误。</p></blockquote><p><strong>自动化部署</strong></p><ol><li>在项目根目录新建文件夹.github/workflows</li><li>在里面新建deploy-pages.yml</li></ol><blockquote><p>文件deploy-pages.yml代码可以参考我的样式：<a href="https://github.com/MeiEddie/MeiEddie.github.io" target="_blank" rel="noreferrer">https://github.com/MeiEddie/MeiEddie.github.io</a></p></blockquote><ol start="3"><li>把新文件也上传仓库</li></ol><p>现在你的文件可能大概应该会长这个样子：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>YourFile/</span></span>
<span class="line"><span>├─ .github/</span></span>
<span class="line"><span>│  └─ workflows/</span></span>
<span class="line"><span>│     └─ deploy.yml   ← GitHub Actions自动部署脚本</span></span>
<span class="line"><span>├─ docs/</span></span>
<span class="line"><span>│  ├─ .vitepress/</span></span>
<span class="line"><span>│  │  └─ config.mjs  #网站全局配置</span></span>
<span class="line"><span>│  ├─ index.md  #博客首页</span></span>
<span class="line"><span>│  ├─ api-examples.md  #官方示例（可删除）</span></span>
<span class="line"><span>│  └─ markdown-examples.md # 官方示例（可删除）</span></span>
<span class="line"><span>├─ node_modules/  # vitepress依赖包（npm install生成，不需要上传）</span></span>
<span class="line"><span>├─ package-lock.json</span></span>
<span class="line"><span>└─ package.json</span></span></code></pre></div><ol start="4"><li>上传之后，你需要检查仓库Actions有没有正常运行</li></ol><blockquote><p>绿色勾是成功，黄色圆圈是等待中，红色叉叉是失败。这里因为文件deploy-pages.yml的代码不同需要自己调试，建议直接扔给AI</p></blockquote><ol start="5"><li>开启GitHub Pages服务：</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Settings/Pages</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Build and deployment下：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Source选择Deploy from a branch</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Branch选择gh-pages，文件夹选/ (root)</span></span></code></pre></div><p>等个一两分钟网址应该就出来了，记住不要选择Github Actions</p>`,82)])])}const b=a(n,[["render",t]]);export{u as __pageData,b as default};
